class Solution(object):
    def findWords(self, words):
        rows = [set('qwertyuiop'), set('asdfghjkl'), set('zxcvbnm')]
        result = []
        for word in words:
            word_lower = word.lower()
            for row in rows:
                if all(c in row for c in word_lower):
                    result.append(word)
                    break
        return result
